@startuml
package "org" {
    package "accordproject" {
        folder empty {
            class EmptyClause <<Asset>> #008000
            class Clause <<Concept>> #90EE90

            ' Relationship from Asset to Concept - using dashed line for inheritance-like connection in this context
            [EmptyClause] ..> [Clause] : extends
        }

        folder contract {
            class Request <<Transaction>> #FFFF00
            class Response <<Event>> #FFA500
        }

        folder runtime {
            class Transaction <<Interface>> 
            class Event <<Abstract Class>> 

            ' Relationships showing implementation/inheritance hierarchy
            [Request] --|> [Transaction]
            [Response] --|> [Event]

            note right of Transaction\n#lightgray This represents base transaction type\ntypically used across all contracts endnote
            note left of Event\n#lavender Base event structure\nfor system notifications endnote
        }
    }
}

' Additional styling notes based on common patterns observed:
skinparam backgroundColor white
skinparam defaultFontName Arial
hide circle
legend position bottom center
end legend

@enduml
